property.value:
//Annotation[
    ancestor::ClassDeclaration[
        ancestor::PackageDeclaration[contains(@Name,'.domain')]
    ]
    and (
        @SimpleName = 'Entity'
        or @SimpleName = 'Table'
        or @SimpleName = 'Column'
        or @SimpleName = 'ManyToOne'
        or @SimpleName = 'OneToMany'
        or @SimpleName = 'ManyToMany'
    )
]

//ClassDeclaration[
    (ends-with(@SimpleName,'Controller') or ends-with(@SimpleName,'Resource'))
    and .//FieldDeclaration[
        ClassType[
            ends-with(@SimpleName,'Repository')
            or ends-with(@SimpleName,'DAO')
            or contains(@SimpleName,'Jdbc')
        ]
    ]
]

//StringLiteral[
    contains(@Image,'sgconnect')
    or contains(@Image,'oauth2/authorize')
    or contains(@Image,'oauth2/token')
    or contains(@Image,'.authentication.')
]

//VariableDeclarator[
    (contains(lower-case(@Name),'port') or contains(lower-case(@Name),'host'))
    and NumericLiteral[
        @IntLiteral = true()
        and (@Image = '8080' or @Image = '8443' or @Image = '5432'
            or @Image = '3306' or @Image = '5672' or @Image = '9092')
    ]
]

//MethodCall[
    @MethodName='mock'
    and ancestor::ClassDeclaration[ends-with(@SimpleName,'Test')]
    and ArgumentList/ClassType[
        not(ends-with(@SimpleName,'Client'))
        and not(ends-with(@SimpleName,'Gateway'))
        and not(ends-with(@SimpleName,'Adapter'))
        and not(ends-with(@SimpleName,'Repository'))
    ]
]
